 41→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 42→  const nextWall = { ...existingWall, ...wallUpdate };
 43→
 44→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 45→    nextWall.startAttachment = null;
 46→  }
 47→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 48→    nextWall.endAttachment = null;
 49→  }
 50→
 51→  return syncWallAttachmentPoints(nextWall, columns);
 52→}
