170→export function EditorProvider({ children, activeFloorId }) {
171→  const [state, dispatch] = useReducer(
172→    editorReducer,
173→    activeFloorId,
174→    createInitialEditorState
175→  );
176→
177→  useEffect(() => {
178→    if (activeFloorId && activeFloorId !== state.activeFloorId) {
179→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: activeFloorId });
180→    }
181→  }, [activeFloorId]);
182→
183→  return (
184→    <EditorContext.Provider value={{ state, dispatch }}>
185→      {children}
186→    </EditorContext.Provider>
187→  );
188→}
